import {HttpResponse, HttpStatus} from "../../todoist/TodoistApi";

export async function parseResponse<Res = undefined>(response: Response): Promise<HttpResponse<Res>> {
    return {
        status: response.status as HttpStatus,
        successful: response.ok,
        body: await tryParseJson<Res>(response.text())
    }
}

function tryParseJson<T= undefined>(body: Promise<string>): Promise<T> {
    return body.then(value => {
        if (value) {
            return JSON.parse(value)
        }
    })
}
