import {useStoreState} from "../store";
import Working from "./Working";
import {clock} from "../domain/Clock";


function WorkPage() {
    const tasks = useStoreState(state => state.readyToDos);

    return <>
        {tasks.length > 0 ? <Working tasks={tasks.filter(task=> task.dueDate <= clock.today())}/> : <div>No tasks</div>}
    </>
}

export default WorkPage
