import {TaskId} from "../shared/TaskId";
import {Priority} from "../shared/Priority";
import styles from "./Progress.module.css";
import {priorityColor} from "../shared/priorityColor";
import {Minutes} from "../shared/Minutes";
import {classNameIf, classNames} from "../shared/components/className";
import Skeleton from "../shared/components/Skeleton";
import {useHotkeys} from "react-hotkeys-hook";
import {useState} from "react";
import {Keys} from "react-hotkeys-hook/src/types";
import {Estimation} from "../domain/task";
import {useEstimationLabels} from "../shared/useEstimationLabels";

interface ProgressProps {
    currentId: TaskId;
    tasks: WorkableTask[];
    availableMinutes: Minutes;
    loading: boolean;
}

export interface WorkableTask {
    id: TaskId;
    priority: Priority;
    usedTime: Minutes;
    estimation: Estimation;
}



function useIsHotkeyPressedDown(keys: Keys) {
    const [pressedDown, setPressedDown] = useState(false);

    useHotkeys(keys, () => setPressedDown(true), {keyup: false});

    useHotkeys(keys, () => setPressedDown(false), {keyup: true});
    return pressedDown

}

function Progress({tasks, currentId, availableMinutes, loading}: ProgressProps) {

    const showDurationBased = useIsHotkeyPressedDown("space");

    return <Skeleton enabled={loading}>
        {showDurationBased ?
            <div className={styles.Tasks}>
                {tasks.map(task => {
                    const isOverdue = task.usedTime >= availableMinutes!;
                    return <DurationBased key={task.id} task={task} isOverdue={isOverdue}
                                          currentId={currentId}/>
                })}
            </div>:
            <div className={styles.Tasks}>
                {tasks.map(task => {
                    const isOverdue = task.usedTime >= availableMinutes!;
                    return <PriorityBased key={task.id} task={task} isOverdue={isOverdue} currentId={currentId}/>
                })}
            </div>
        }
    </Skeleton>
}

interface PriorityBasedProps {
    task: WorkableTask;
    isOverdue: boolean;
    currentId: TaskId;
}

function PriorityBased({task, isOverdue, currentId}: PriorityBasedProps) {
    const color = priorityColor(task.priority);
    return <div key={task.id}
                className={classNames(styles.Task, classNameIf(isOverdue, styles.Overdue))}
                style={{
                    borderColor: color,
                    backgroundColor: task.id === currentId ? color : "transparent"
                }}/>
}

interface DurationBasedProps {
    task: WorkableTask;
    isOverdue: boolean;
    currentId: TaskId;
}

function DurationBased({task, isOverdue, currentId}: DurationBasedProps) {
    const estimationLabels = useEstimationLabels();
    const color = estimationLabels[task.estimation.code].color;
    return <div
        className={classNames(styles.Task, classNameIf(isOverdue, styles.Overdue))}
        style={{
            flexShrink: 0,
            borderColor: color,
            backgroundColor: task.id === currentId ? color : "transparent",
            width: task.estimation.duration * 2
        }}/>
}

export default Progress
