import React from 'react';
import './App.css';
import Layout from "./layout/Layout";
import {BrowserRouter, Route, Routes} from "react-router-dom";
import SettingsPage from "./settings/SettingsPage";
import Initialize from "./init/Initialize";
import EstimatePage from "./estimate/EstimatePage";
import WorkPage from "./work/WorkPage";
import PlanPage from "./plan/PlanPage";
import HotkeysProviderWithDefaultScopes from "./shared/hotkeys/HotkeysProviderWithDefaultScopes";

function App() {

    return (
        <HotkeysProviderWithDefaultScopes>
            <BrowserRouter>
                <Routes>
                    <Route index element={<Initialize/>}/>
                    <Route element={<Layout/>}>
                        <Route path="/estimate" element={<EstimatePage/>}/>
                        <Route path="/work" element={<WorkPage/>}/>
                        <Route path="/plan/:day" element={<PlanPage/>}/>
                        <Route path="/settings" element={<SettingsPage/>}/>
                    </Route>
                </Routes>
            </BrowserRouter>
        </HotkeysProviderWithDefaultScopes>

    );
}


export default App;
