import HotkeyConfirmation from "../shared/hotkeys/HotkeyConfirmation";
import {TaskId} from "../shared/TaskId";
import If from "../shared/components/If";
import {RescheduleTaskPayload} from "../store";
import {ColorKey, getColorByKey, Hex} from "../shared/Color";
import {Period} from "../shared/Period";

type Action = { label: string, amount: number, unit: "day" | "days" | "week" | "weeks", color?: Hex }

const actions: Action[] = [
    {
        label: "1 Week",
        amount: 1,
        unit: "week",
        color: getColorByKey(ColorKey.SKY_BLUE).value
    },
    {
        label: "2 Weeks",
        amount: 2,
        unit: "weeks",
        color: getColorByKey(ColorKey.LIGHT_BLUE).value
    },
]

interface RescheduleDayProps {
    onReschedule: (period: Period) => void
}

export function RescheduleDay({onReschedule}: RescheduleDayProps) {

    return <>
        {actions.map(({label, amount, unit, color}, index) => {
            return <HotkeyConfirmation
                key={index}
                binding={`shift + ${index + 1}`}
                action={() => {
                    onReschedule({amount, unit})
                }}
                label={label}
                color={color}
            />
        })}
    </>;
}
