import {
    action,
    Action,
    computed,
    Computed,
    createStore,
    createTypedHooks,
    thunk,
    Thunk,
    thunkOn,
    ThunkOn
} from 'easy-peasy';
import {asLabels, isTimeLabel} from "./todoist/asLabels";
import {LabelName} from "./shared/LabelName";
import {Task} from "./domain/task";
import {TaskId} from './shared/TaskId';
import {todoistApi} from "./todoist/TodoistApi";
import {Priority} from "./shared/Priority";
import {asTaskFromApi, asTasksFromApi, tryExtractEstimationFrom} from "./todoist/asTasks";
import {sortTasks} from "./estimate/sortTasks";
import {DoableTask} from "./work/DoableTask";
import asDoableTask from "./work/asDoableTask";
import {clock} from "./domain/Clock";
import {DayOverview} from "./plan/DayOverview";
import {Label, LabelCategory} from "./domain/Label";
import {InProgressTask} from "./work/InProgressTask";
import dayjs from "dayjs";
import {DueDate, dueDateFrom} from "./todoist/DueDate";
import {dueDate} from "./shared/dueDate";
import {Period} from "./shared/Period";
import {LocalRepository} from "./infrastructure/localstorage/LocalRepository";
import LocalStorageRepository from "./infrastructure/localstorage/LocalStorageRepository";
import {Configuration} from "./configuration/Configuration";
import {DailyTaskOrder, orderRepository, WorkingPlan} from "./work/OrderRepository";
import {Day} from "./domain/Day";
import {Area, Severity} from "./shared/components/Indicator";
import {IndicatorStore} from "./IndicatorStore";
import {Minutes} from "./shared/Minutes";
import {workCapacityLeft} from "./work/useMinutesUntil";
import debounce from "lodash/debounce";
import {v4} from "uuid";


const inProgressTaskRepository: LocalRepository<InProgressTask> = new LocalStorageRepository<InProgressTask>("__in_progress_task")
const configRepository: LocalRepository<Configuration> = new LocalStorageRepository<Configuration>("__configuration")

const lookupTodoistApi = () => todoistApi(configRepository)

export const DAY_LIMIT = "20:00";

export interface RescheduleDayPayload {
    taskIds: TaskId[],
    dueDate: DueDate
}

export interface RescheduleTaskPayload {
    taskId: TaskId,
    period: Period
}

export interface StoreModel {
    syncing: string[];
    startSyncing: Action<StoreModel, string>;
    stopSyncing: Action<StoreModel, string>;


    tasks: Record<TaskId, Task>;
    createNewTask: Thunk<StoreModel, {content: string, dueDate: DueDate}>
    addTask: Action<StoreModel, Task>;
    overview: Computed<this, Record<Day, DayOverview>>;
    processingTasks: boolean;
    setProcessingTasks: Action<this, boolean>;
    labels: Record<LabelName, Label>;
    timeLabels: Computed<this, Label[]>;
    toEstimate: Computed<this, Task[]>;
    completeTask: Thunk<StoreModel, TaskId>;
    setTasks: Action<StoreModel, Task[]>;
    replaceLabels: Action<StoreModel, { taskId: TaskId, labels: LabelName[] }>;
    replacePriority: Action<StoreModel, { taskId: TaskId, priority: Priority }>;
    replaceDueDate: Action<StoreModel, { taskIds: TaskId[], dueDate: DueDate }>;
    removeTask: Action<StoreModel, TaskId>;
    setLabels: Action<StoreModel, Label[]>;
    fetchTasksAndLabels: Thunk<StoreModel>;
    addLabel: Thunk<StoreModel, { label: LabelName, taskId: TaskId }>;
    estimate: Thunk<StoreModel, { label: LabelName, taskId: TaskId }>;
    rescheduleTasks: Thunk<StoreModel, RescheduleDayPayload>;
    changePriority: Thunk<StoreModel, { priority: Priority, taskId: TaskId }>;
    rescheduleTask: Thunk<StoreModel, RescheduleTaskPayload>;

    readyToDos: Computed<this, DoableTask[]>;

    inProgressTask?: InProgressTask;
    startWorkingOnTask: Action<StoreModel, TaskId>;
    stopWorkingOnTask: Action<StoreModel, TaskId>;
    workingTasksOrder: WorkingPlan;
    taskOrderMove: Action<StoreModel, { day: Day, taskId: TaskId, operation: 'higher' | 'lower' | 'lowest' | 'highest' }>;
    onTaskReorder: ThunkOn<StoreModel>;
    todayWorkingTasksOrder: Computed<this, TaskId[]>;

    indicator: Computed<this, IndicatorStore | undefined>;
    workCapacity: Computed<this, Minutes>;
}

function indicator(severity: Severity, area: Area, alwaysVisible?: boolean): IndicatorStore {
    return {severity, area, alwaysVisible};
}

const debouncedStoreInRepository = debounce((startSyncing: () => void, day: Day, order: DailyTaskOrder) => {
    startSyncing()
    return orderRepository.store(day, order)
}, 2000);

const storeModel: StoreModel = {
    tasks: {},
    labels: {},
    syncing: [],

    startSyncing: action((state, payload) => {
            state.syncing.push(payload)
        }
    ),
    stopSyncing: action((state, payload) => {
            state.syncing = state.syncing.filter(it => it !== payload)
        }
    ),

    processingTasks: false,
    setProcessingTasks: action((state, payload) => {
            state.processingTasks = payload;
        }
    ),
    timeLabels: computed((state) =>
        Object.values(state.labels)
            .filter(label => label.category === LabelCategory.ESTIMATION)
            .sort((a, b) => a.order - b.order)
    ),
    toEstimate: computed((state) =>
        Object.values(state.tasks)
            .filter(task => task.dueDate && !task.estimation)
            .filter(task => task.dueDate! <= dueDate.today())
            .sort(sortTasks)
    ),
    addTask: action((state, task) => {
        state.tasks[task.id] = task
    }),
    createNewTask: thunk(async (actions, {content, dueDate}) => {
            const taskResponse = await lookupTodoistApi().createTask({
                content,
                due_date: dueDate
            }).then(response => response.body);
            actions.addTask(asTaskFromApi(taskResponse))
        }
    ),
    setTasks: action((state, tasks) => {
        state.tasks = tasks.reduce((prev, curr) => {
                let id = curr.id;
                prev[id] = curr
                return prev;
            }
            , {} as Record<TaskId, Task>);
    }),
    overview: computed((state) => {
        return Object.values(state.readyToDos).reduce((prev, curr) => {
                let dueDate = curr.dueDate;
                let dayOverview: DayOverview = prev[dueDate!] || {tasksAmount: 0};
                dayOverview.tasksAmount++;
                prev[dueDate!] = dayOverview
                return prev;
            }
            , {} as Record<Day, DayOverview>);
    }),

    replaceLabels: action((state, {taskId, labels}) => {
        let task = state.tasks[taskId];
        task.labels = labels;
        task.estimation = tryExtractEstimationFrom(labels)
    }),
    replaceDueDate: action((state, {taskIds, dueDate}) => {
        taskIds.forEach(taskId => {
            let task = state.tasks[taskId];
            task.dueDate = dueDate;
        })
    }),
    replacePriority: action((state, {taskId, priority}) => {
        state.tasks[taskId].priority = priority;
    }),
    removeTask: action((state, taskId) => {
        delete state.tasks[taskId]
    }),
    setLabels: action((state, labels) => {
        state.labels = labels.reduce((prev, curr) => {
                let name = curr.name;
                prev[name] = curr
                return prev;
            }
            , {} as Record<LabelName, Label>);
    }),
    fetchTasksAndLabels: thunk(async (actions) => {
            let projects = await lookupTodoistApi().getProjects();
            let inboxProjectId = projects.find(project => project.is_inbox_project)!.id;

            const [tasksResponse, labelsResponse] = await Promise.all([
                lookupTodoistApi().getTasks(),
                lookupTodoistApi().getLabels(),
            ]);
            let receivedTasks = tasksResponse.body;
            let tasks = asTasksFromApi(receivedTasks.filter(task => task.project_id === inboxProjectId));
            actions.setTasks(tasks);
            actions.setLabels(asLabels(labelsResponse));

        }
    ),
    completeTask: thunk(async (actions, taskId) => {
            actions.setProcessingTasks(true);
            try {
                await lookupTodoistApi().closeTask(taskId);
                actions.removeTask(taskId)
            } finally {
                actions.setProcessingTasks(false);
            }

        }
    ),
    addLabel: thunk(async (actions, {label, taskId}, {getState}) => {
            let task = getState().tasks[taskId]
            if (task) {
                actions.setProcessingTasks(true);
                let labels = [label, ...task.labels];
                try {
                    let taskId = task.id;
                    let response = await lookupTodoistApi().replaceLabels(taskId, labels);
                    if (response.successful) {
                        actions.replaceLabels({
                            taskId,
                            labels
                        })
                    }

                } finally {
                    actions.setProcessingTasks(false);
                }

            }
        }
    ),

    estimate: thunk(async (actions, {label, taskId}, {getState}) => {
            let task = getState().tasks[taskId]
            if (task && isTimeLabel(label)) {
                actions.setProcessingTasks(true);
                let labels = [label, ...task.labels.filter(l => !isTimeLabel(l))];
                try {
                    let taskId = task.id;
                    let response = await lookupTodoistApi().replaceLabels(taskId, labels);
                    if (response.successful) {
                        actions.replaceLabels({
                            taskId,
                            labels
                        })
                    }

                } finally {
                    actions.setProcessingTasks(false);
                }

            }
        }
    ),
    changePriority: thunk(async (actions, {priority, taskId}, {getState}) => {
            const task = getState().tasks[taskId];
            if (task.priority !== priority) {
                actions.setProcessingTasks(true);
                try {
                    let response = await lookupTodoistApi().updateTask(taskId, {
                        priority: priority
                    });

                    if (response.successful) {
                        actions.replacePriority({taskId, priority})
                    }
                } finally {
                    actions.setProcessingTasks(false);
                }

            }
        }
    ),
    rescheduleTask: thunk(async (actions, {period: {amount, unit}, taskId}) => {
            actions.setProcessingTasks(true);
            try {
                const newDueDate = dueDateFrom(dayjs().add(amount, unit));
                let response = await lookupTodoistApi().updateTask(taskId, {
                    due_date: newDueDate
                });

                if (response.successful) {
                    actions.replaceDueDate({ taskIds: [taskId], dueDate: newDueDate})
                }
            } finally {
                actions.setProcessingTasks(false);
            }
        }
    ),
    rescheduleTasks: thunk(async (actions, {taskIds, dueDate}) => {
            actions.setProcessingTasks(true);
            try {
                let response = await lookupTodoistApi().updateDueDateTasks(taskIds,dueDate);

                if (response.successful) {
                    actions.replaceDueDate({taskIds, dueDate: dueDate})
                }
            } finally {
                actions.setProcessingTasks(false);
            }

        }
    ),
    readyToDos: computed((state) =>
        Object.values(state.tasks)
            .filter(task => task.dueDate)
            .filter(task => task.estimation)
            .map(task => asDoableTask(task, clock.today()))
            // .filter(task => task.dueDate <= dueDate.today())
            .sort(sortTasks)
    ),

    workCapacity: computed((state) =>
        state.readyToDos.reduce((acc, task) => {
            acc += task.estimation.duration
            return acc;
        }, 0)
    ),

    inProgressTask: inProgressTaskRepository.find(),


    startWorkingOnTask: action((state, taskId) => {
        const inProgressTask: InProgressTask = {
            id: taskId,
            startedAt: clock.now()
        };
        state.inProgressTask = inProgressTask
        inProgressTaskRepository.store(inProgressTask);
    }),

    stopWorkingOnTask: action((state, taskId) => {
        state.inProgressTask = undefined;
        inProgressTaskRepository.delete();
    }),

    workingTasksOrder: orderRepository.load(),

    taskOrderMove: action((state, {day, taskId, operation}) => {
        let workingPlan = state.workingTasksOrder[day];
        if (!workingPlan) {
            workingPlan = state.readyToDos.filter(doable => doable.effectiveDueDate === day).map(doable => doable.id)
            state.workingTasksOrder[day] = workingPlan
        }
        switch (operation) {
            case "highest":
                state.workingTasksOrder[day] = workingPlan.moveFirst(taskId)
                break;
            case "higher":
                state.workingTasksOrder[day] = workingPlan.moveLeft(taskId)
                break;
            case "lower":
                state.workingTasksOrder[day] = workingPlan.moveRight(taskId)
                break;
            case "lowest":
                state.workingTasksOrder[day] = workingPlan.moveLast(taskId)
                break;
        }
    }),
    onTaskReorder: thunkOn(
        (actions, storeActions) => actions.taskOrderMove,
        async (actions, {payload: {day}}, {getState}) => {
            function startSync() {
            }

            try {
                await debouncedStoreInRepository(startSync, day, getState().workingTasksOrder[day])
            } finally {
            }

        }
    ),


    todayWorkingTasksOrder: computed((state) =>
        state.workingTasksOrder[clock.today()] || []
    ),


    indicator: computed((state) => {
            if (state.inProgressTask) {
                return indicator(Severity.URGENT, Area.WORK)
            }
            if (state.toEstimate.length > 0) {
                return indicator(Severity.BASIC, Area.ESTIMATION)
            }

            if (state.workCapacity > workCapacityLeft(DAY_LIMIT)) {
                return indicator(Severity.WARN, Area.WORK, true)
            }

            if (state.readyToDos.length > 0) {
                return indicator(Severity.INFO, Area.WORK)
            }

        }
    ),
};

const store = createStore(storeModel);

export default store;

const typedHooks = createTypedHooks<StoreModel>();

export const useStoreActions = typedHooks.useStoreActions;
export const useStoreDispatch = typedHooks.useStoreDispatch;
export const useStoreState = typedHooks.useStoreState;
