import styles from "./Layout.module.css"
import Navigate from "../shared/Navigate";
import {Outlet} from "react-router-dom";
import Menu from "../menu/Menu";
import Syncing from "./Syncing";
import NewTask from "../task/NewTask";
import Icon from "../shared/Icon";
import {SettingsMenuItem} from "../settings/SettingsMenuItem";

interface LayoutProps {
    colored?: boolean
}


function Layout({colored}: LayoutProps) {

    function colorStyle(color: string) {
        return {backgroundColor: colored ? color : undefined};
    }

    return <div className={styles.LayoutContainer}>
        <div className={styles.Header} style={colorStyle("red")}>
            <Navigate to="/">
                <Icon size={32} name="todoist.svg"/>
            </Navigate>
            <div className={styles.HeaderContent} id="header-portal"/>
            <Syncing/>
            <SettingsMenuItem/>
        </div>
        <div className={styles.MainContent}>
            <NewTask/>
            <Outlet/>
        </div>
        <div className={styles.Footer} style={colorStyle("red")}>
            <div id="footer-portal" className={styles.HeaderContent}/>
        </div>
        <div className={styles.SidebarLeft} style={colorStyle("yellow")}>
            <Menu/>
            <div id="sidebar-left-portal"/>
        </div>
        <div className={styles.SidebarRight} style={colorStyle("yellow")}>
            <div id="sidebar-right-portal"/>
        </div>
    </div>
}

export default Layout
