import SidebarRight from "../layout/SidebarRight";
import Overview from "./Overview";
import {Clock} from "../domain/Clock";
import {RealClock} from "../domain/RealClock";
import {RescheduleTaskPayload, useStoreActions, useStoreState} from "../store";
import {Task} from "../domain/task";
import {useParams} from "react-router-dom";
import {useEffect, useState} from "react";
import {DailyTask} from "./DailyTask";
import {DailyTasks} from "./DailyTasks";
import Footer from "../layout/Footer";
import {HotKey} from "../shared/hotkeys/HotKey";
import {TaskId} from "../shared/TaskId";
import styles from "./PlanPage.module.css"
import {RescheduleTask} from "./RescheduleTask";
import {usePlanParam} from "./usePlanParam";
import {useHotkeys} from "react-hotkeys-hook";
import {RescheduleDay} from "./RescheduleDay";
import {Period} from "../shared/Period";
import {onDayAdd} from "../domain/Day";
import Icon from "../shared/Icon";
import HotkeyConfirmation from "../shared/hotkeys/HotkeyConfirmation";


function PlanPage() {
    let clock: Clock = new RealClock();

    const [dailyTasks, setDailyTasks] = useState<DailyTask[]>([]);
    const [selectedItem, setSelectedItem] = useState<TaskId | undefined>();
    const {overview: dayOverviews, readyToDos: tasks, processingTasks} = useStoreState(state => state);
    const {day} = useParams();
    const {day: effectiveDay} = usePlanParam();
    const {rescheduleTask, rescheduleTasks, taskOrderMove, completeTask} = useStoreActions(actions => actions);

    function filterByDay(task: Task): boolean {
        if (day === "today") {
            return task.dueDate! <= clock.today();
        }
        return task.dueDate! === day;
    }

    function performRescheduleTask(payload: RescheduleTaskPayload) {
        const index = dailyTasks.map(it => it.id).indexOf(selectedItem!);
        rescheduleTask(payload)
        setSelectedItem(dailyTasks[Math.min(index, dailyTasks.length - 1)].id)
    }

    function performRescheduleDay(period: Period) {
        const newDueDate = onDayAdd(effectiveDay, period);
        rescheduleTasks({taskIds: dailyTasks.map(it => it.id), dueDate: newDueDate})
    }

    useEffect(() => {
        setDailyTasks(tasks
            .map(({id, ...rest}) => ({
                id,
                selected: id === selectedItem, ...rest
            }))
            .filter(filterByDay)
        );
        setSelectedItem(dailyTasks.find(task => task.id === selectedItem)?.id)
    }, [day, selectedItem, tasks]);

    useEffect(() => {
        setSelectedItem(dailyTasks.find(task => task.id === selectedItem)?.id)
    }, [dailyTasks]);

    useHotkeys("esc", () => {
        setSelectedItem(undefined);
    }, {
        scopes: "default"
    })

    function hasNext(): boolean {
        if (selectedItem) {
            return dailyTasks.map(it => it.id).next(selectedItem) !== undefined
        }
        return dailyTasks.length > 0;
    }


    function hasPrevious(): boolean {
        if (selectedItem) {
            return dailyTasks.map(it => it.id).previous(selectedItem) !== undefined
        }
        return dailyTasks.length > 0;
    }

    function selectPrevious() {
        setSelectedItem((prev) => {
            return prev ? dailyTasks.map(it => it.id).previous(prev) : dailyTasks.last()?.id
        })
    }

    function performComplete() {
        if (selectedItem) {
            completeTask(selectedItem);
        }
    }

    function selectNext() {
        setSelectedItem((prev) => {
            return prev ? dailyTasks.map(it => it.id).next(prev) : dailyTasks.first()?.id
        })
    }

    function onSelectTask(taskId: TaskId) {
        setSelectedItem((prev) => prev !== taskId ? taskId : undefined)
    }

    return <>
        <div className={styles.Ordering}>
            <HotKey binding="shift + up"
                    label="Up"
                    disabled={!!selectedItem}
                    onClick={() => taskOrderMove({
                        taskId: selectedItem!,
                        day: effectiveDay,
                        operation: "higher"
                    })}/>
            <HotKey binding="shift + down"
                    label="Down"
                    disabled={!!selectedItem}
                    onClick={() => taskOrderMove({
                        taskId: selectedItem!,
                        day: effectiveDay,
                        operation: "lower"
                    })}/>
        </div>

        <DailyTasks tasks={dailyTasks} onSelectTask={onSelectTask}/>
        <SidebarRight>
            <Overview today={clock.today()} overview={dayOverviews}/>
        </SidebarRight>
        <Footer>
            <div className={styles.Footer}>
                <div className={styles.Actions}>
                    {selectedItem && <HotkeyConfirmation
                        binding="shift + enter"
                        action={performComplete}
                        label={<Icon name="check.svg"/>}
                        loading={processingTasks}/>}

                    {selectedItem && <RescheduleTask
                        taskId={selectedItem}
                        onReschedule={performRescheduleTask}
                    />}
                    {!selectedItem && dailyTasks.length > 0 && <RescheduleDay
                        onReschedule={performRescheduleDay}
                    />}
                </div>
                <div className={styles.Selections}>
                    <HotKey binding="up" label="Prev" onClick={selectPrevious} disabled={!hasPrevious()}/>
                    <HotKey binding="down" label="Next" onClick={selectNext} disabled={!hasNext()}/>
                </div>
            </div>

        </Footer>
    </>
}

export default PlanPage
