import {PropsWithChildren} from "react";
import styles from "./MenuItem.module.css"
import {useLocation, useNavigate} from "react-router-dom";
import {classNameIf, classNames} from "../shared/components/className";
import {useHotkeys} from "react-hotkeys-hook";
import Indicator, {Area} from "../shared/components/Indicator";
import Icon from "../shared/Icon";


export interface MenuItemProps {
    path: string;
    shortcut: string;
    icon: string;
    area: Area;
}

function MenuItem({path, shortcut, icon, area, children}: PropsWithChildren<MenuItemProps>) {

    let {pathname} = useLocation();
    useHotkeys(shortcut, () => performNavigate())

    let navigate = useNavigate();

    const performNavigate = () => {
        navigate(path)
        return false;
    }

    const isActive = pathname.startsWith(path)

    return <div onClick={performNavigate}
                className={classNames(classNameIf(isActive, styles.Active), styles.Item)}>
        <Indicator area={area} visible={!isActive}>
            <Icon name={icon}/>
        </Indicator>
        <div className={styles.Text}>
            {children}
        </div>
    </div>
}

export default MenuItem
