import {extractMinutesFrom, timeLabelRegex} from "./asLabels";
import {Estimation, Task} from "../domain/task";
import {LabelName} from "../shared/LabelName";
import {TaskApiResponse} from "./TaskApiResponse";

export function tryExtractEstimationFrom(labels: LabelName[]): Estimation | undefined {
    const found = labels.find(labelName => timeLabelRegex.test(labelName));
    return found ? { code: found, duration: extractMinutesFrom(found)} : undefined;
}


export function asTaskFromApi(item: TaskApiResponse): Task {
    return {
        id: item.id,
        content: item.content,
        labels: item.labels,
        estimation: tryExtractEstimationFrom(item.labels),
        dueDate: item.due?.date,
        priority: item.priority,
    };
}

export function asTasksFromApi(input: TaskApiResponse[]): Task[] {
    return input.map(item => asTaskFromApi(item));
}

