import {DoableTask} from "./DoableTask";
import React, {PropsWithChildren} from "react";
import styles from "./Work.module.css"
import {HumanizedDay} from "../shared/humanizeDueDay";
import {ColorKey, getColorByKey} from "../shared/Color";
import Skeleton from "../shared/components/Skeleton";

export interface WorkPros {
    task: DoableTask,
    humanizedDay: HumanizedDay,
    loading: boolean
}

function Work({task, humanizedDay, children, loading}: PropsWithChildren<WorkPros>) {
    return <div>
        <Skeleton enabled={loading}>
            <div className={styles.Header}>
                <h1>{task.content}</h1>
            </div>
        </Skeleton>
        <Skeleton enabled={loading}>
            <div className={styles.Day}
                 style={{borderColor: humanizedDay.dayDiff < 0 ? getColorByKey(ColorKey.RED).value : undefined}}>{humanizedDay.text}
            </div>
        </Skeleton>
        {children}
    </div>
}

export default Work;
