import {LocalRepository} from "./LocalRepository";

class LocalStorageRepository<T> implements LocalRepository<T> {
    private readonly key: string;

    constructor(key: string) {
        this.key = key;
    }

    store(item: T): void {
        try {
            const serializedItem = JSON.stringify(item);
            localStorage.setItem(this.key, serializedItem);
        } catch (error) {
            console.error('Error saving to localStorage', error);
        }
    }

    find(): T | undefined {
        try {
            const serializedItem = localStorage.getItem(this.key);
            if (serializedItem != null) {
                return JSON.parse(serializedItem) as T;
            }
        } catch (error) {
            console.error('Error reading from localStorage', error);
        }
    }

    delete(): void {
        try {
            localStorage.removeItem(this.key);
        } catch (error) {
            console.error('Error deleting from localStorage', error);
        }
    }

    exists(): boolean {
        return localStorage.getItem(this.key) !== null;
    }
}

export default LocalStorageRepository;
