import {useStoreActions, useStoreState} from "../store";
import {Timing} from "./Timing";
import {EstimateTask} from "./EstimateTask";
import Footer from "../layout/Footer";
import styles from "./EstimatePage.module.css"
import AllDone from "./AllDone";
import PostponeActions from "./PostponeActions";
import HotkeyConfirmation from "../shared/hotkeys/HotkeyConfirmation";
import Icon from "../shared/Icon";
import {period} from "../shared/Period";

function EstimatePage() {

    let {toEstimate, timeLabels: labels, processingTasks} = useStoreState(state => state)
    let {completeTask, addLabel, rescheduleTask} = useStoreActions(actions => actions);

    let remaining = toEstimate.length;
    let task = toEstimate[0];

    function skipTaskEstimation() {
        rescheduleTask({taskId: task.id, period: period(1, "day")})
    }

    function performCompleteTask() {
        if (task) {
            completeTask(task.id);
        }
    }

    return <>
        {task ? <EstimateTask remaining={remaining} task={task}/> : <AllDone/>}
        {task && <div className={styles.Timings}>
            {labels.map((item, index) =>
                <Timing key={item.name}
                        color={item.color.value}
                        value={item.name}
                        onClick={() => {
                            addLabel({taskId: task!.id, label: item.name})
                        }}
                        binding={`${index + 1}`}
                        disabled={processingTasks}
                />
            )}
        </div>}
        {task && <PostponeActions taskId={task.id}/>}
        <Footer>
            {
                task && <div className={styles.Footer}>
                    <HotkeyConfirmation
                        binding="enter"
                        shortcut="⏎"
                        action={performCompleteTask}
                        label={<Icon name="check.svg"/>}
                        loading={processingTasks}/>

                    <HotkeyConfirmation
                        binding="space"
                        action={skipTaskEstimation}
                        label={<Icon name="forward-step.svg"/>}
                        loading={processingTasks}/>
                </div>
            }
        </Footer>
    </>
}

export default EstimatePage
