import styles from "./TaskItem.module.css"
import PriorityIcon from "../shared/components/PriorityIcon";
import {DailyTask} from "./DailyTask";
import Duration from "./Duration";
import {classNameIf, classNames} from "../shared/components/className";
import {TaskId} from "../shared/TaskId";

interface TaskItemProps {
    task: DailyTask;
    onSelectTask: (taskId: TaskId) => void;
}

function TaskItem({task: {id,selected, priority, content, estimation}, onSelectTask}: TaskItemProps) {
    return <div className={classNames(styles.TaskItem, classNameIf(selected, styles.Selected))} onClick={()=> onSelectTask(id)}>
        <div className={styles.Header}>
            <PriorityIcon value={priority}/>
            <h3>{content}</h3>
        </div>
        <Duration estimation={estimation} selected={selected}/>
    </div>
}

export default TaskItem
