import React, {useEffect, useRef, useState} from 'react';
import {useStoreActions} from "../store";
import {clock} from "../domain/Clock";
import {useHotkeysContext} from "../shared/hotkeys/useHotkeysContext";
import styles from "./NewTask.module.css"
import {useHotkeys} from "react-hotkeys-hook";
import Icon from "../shared/Icon";

function NewTask() {

    const [inputValue, setInputValue] = useState('');
    const [show, setShow] = useState(false);

    const inputRef = useRef<HTMLInputElement>(null);

    const createNewTask = useStoreActions(actions => actions.createNewTask);

    const {enableDefaultScopes, enableOnlyScope} = useHotkeysContext();


    useEffect(() => {
        setTimeout(() => {
            if (show && inputRef.current) {
                inputRef.current.focus();
            }
        }, 0)

    }, [show]);

    useHotkeys("shift + n", () => {
        enableOnlyScope("task-creation")
        setShow(true)
        setInputValue("");
    }, {
        scopes: "default"
    })
    useHotkeys("esc", () => {
        closeTaskCreation();
    }, {
        scopes: "task-creation"
    })

    function closeTaskCreation() {
        enableDefaultScopes();
        setShow(false)
        return false;
    }


    const createTask = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            await createNewTask({content: inputValue, dueDate: clock.today()})
        } finally {
            setInputValue("");
            enableDefaultScopes();
            setShow(false)
        }
        return false

    };


    return <>
        {show && <div className={styles.Overlay}>
            <div className={styles.Modal}>
                <div className={styles.Close} onClick={closeTaskCreation}>
                    <Icon name="x.svg"/>
                </div>
                <form className={styles.Form} onSubmit={createTask}>
                    <label>
                        <input
                            ref={inputRef}
                            className={styles.Input}
                            placeholder="Task Name"
                            type="text"
                            value={inputValue}
                            onChange={(e) => setInputValue(e.target.value)}
                        />
                    </label>
                    <button className={styles.Submit} type="submit">Create</button>
                </form>
            </div>
        </div>}
    </>
        ;
}

export default NewTask;
