import React from 'react';
import {stringifyMinutes} from "../shared/Minutes";
import styles from "./Duration.module.css"
import {useEstimationLabels} from "../shared/useEstimationLabels";
import {Estimation} from "../domain/task";


interface DurationProps {
    estimation: Estimation;
    selected: boolean;
}

function Duration({estimation: {code, duration}, selected}: DurationProps) {
    const labels = useEstimationLabels();

    return <div className={styles.Estimation}>
        <div className={styles.Time}
             style={{visibility: selected ? "visible" : "hidden"}}
        >
            {stringifyMinutes(duration)}
        </div>
        <div className={styles.Duration} style={{
            backgroundColor: labels[code].color,
            width: 4 * duration
        }}></div>
    </div>
}

export default Duration;
