import {useStoreActions, useStoreState} from "../store";
import {TaskId} from "../shared/TaskId";
import styles from "./PostponeActions.module.css"
import {period} from "../shared/Period";
import HotkeyConfirmation from "../shared/hotkeys/HotkeyConfirmation";
import Icon from "../shared/Icon";

interface PostponeActionsProps {
    taskId: TaskId;
}

function PostponeActions({taskId}: PostponeActionsProps) {

    const postponeTask = useStoreActions(actions => actions.rescheduleTask);
    const processingTasks = useStoreState(state => state.processingTasks);
    return <div className={styles.Actions}>
        <HotkeyConfirmation
            binding="shift + 1"
            shortcut="⇧ +1"
            action={() => postponeTask({taskId, period: period(1, "month")})}
            label={<Icon name="forward-step.svg"/>}
            loading={processingTasks}/>
        <HotkeyConfirmation
            binding="shift + 2"
            shortcut="⇧ +2"
            action={() => postponeTask({taskId, period: period(2, "months")})}
            label={<Icon name="forward-fast.svg"/>}
            loading={processingTasks}/>
    </div>
}

export default PostponeActions

