import styles from "./Progress.module.css"
import {ColorKey, getColorByKey, Hex} from "../shared/Color";
import ProgressItem from "../work/ProgressItem";

export interface ProgressProps {
    value: number
}

function color(value: number): Hex | undefined {

    if (value < 4) {
        return undefined
    }
    if (value < 8) {
        return getColorByKey(ColorKey.YELLOW).value
    }
    if (value < 12) {
        return getColorByKey(ColorKey.ORANGE).value
    }
    return getColorByKey(ColorKey.RED).value
}

const range = (n: number) => Array.from({length: n}, (value, key) => key)

function Progress({value}: ProgressProps) {

    return <div className={styles.Progresses}>
        {range(value).map(v => (<ProgressItem key={v} color={color(v)}/>))}
    </div>


}

export default Progress
