import {useEffect} from "react";
import styles from "./Initialize.module.css"
import Svg from "../shared/Svg";
import {useStoreActions} from "../store";
import {useNavigate} from "react-router-dom";


function Initialize() {
    let navigate = useNavigate();

    const fetchTasksAndLabels = useStoreActions((actions) => actions.fetchTasksAndLabels);

    useEffect(() => {
        fetchTasksAndLabels()
            .then(() => navigate("/estimate"))
    }, []);

    return <div className={styles.Initialize}>
        <div className={styles.Loader}>
            <Svg size={128} src="/assets/icons/settings.svg"/>
        </div>
    </div>;
}

export default Initialize
