import {ProjectId, TodoistProject} from "./ProjectResponse";
import {LabelResponse} from "./LabelResponse";
import {TaskApiResponse} from "./TaskApiResponse";
import {TaskId} from "../shared/TaskId";
import {LabelName} from "../shared/LabelName";
import {LabelId} from "../shared/LabelId";

import {getApiKey} from "./getApiKey";
import {parseResponse} from "../infrastructure/http/parseResponse";
import {SyncQueryType} from "./SyncQueryType";
import {SyncItemsResponse} from "./SyncItemResponse";
import {
    SyncAddItemArgs,
    SyncAddItemRequest,
    SyncCommandRequest,
    SyncItemsUpdateArgs,
    SyncItemsUpdateRequest
} from "./SyncCommandRequest";
import {v4 as randomUUID} from "uuid"
import {SyncCommandResponse} from "./SyncCommandResponse";
import {CreateTaskApiRequest} from "./CreateTaskApiRequest";
import {CreateProjectRequest} from "./CreateProjectRequest";
import {CreateLabelApiRequest} from "./CreateLabelApiRequest";
import {UpdateTaskApiRequest} from "./UpdateTaskApiRequest";
import {LocalRepository} from "../infrastructure/localstorage/LocalRepository";
import {Configuration} from "../configuration/Configuration";
import {DueDate} from "./DueDate";

export function todoistApi(repository?: LocalRepository<Configuration>) {
    return TodoistApi.instance(repository);
}

export interface HttpResponse<T = undefined> {
    body: T
    successful: boolean,
    status: HttpStatus
}

export enum HttpStatus {
    OK = 200,
    NO_CONTENT = 204,
    NOT_FOUND = 404,
    INTERNAL_SERVER_ERROR = 500
}

export class TodoistApi {

    static _instance: TodoistApi

    private apiUrl: string = 'https://api.todoist.com';
    private readonly apiKey: string;

    constructor(apiKey: string) {
        if (!apiKey) {
            throw new Error('API key is required');
        }
        this.apiKey = apiKey;
    }

    public static instance(repository?: LocalRepository<Configuration>): TodoistApi {
        if (!TodoistApi._instance) {
            const keyStored = repository?.exists();

            const apiKey = repository?.find()?.todoistApiKey || getApiKey();
            TodoistApi._instance = new TodoistApi(apiKey);
            if (!keyStored) {
                repository?.store({
                    todoistApiKey: apiKey
                })
            }
        }

        return TodoistApi._instance;
    }

    public async getTasksBySync(): Promise<HttpResponse<SyncItemsResponse>> {
        return this.makeSyncQueryRequest<SyncItemsResponse>(SyncQueryType.ITEMS);
    }

    public async createTasks(args: SyncAddItemArgs[]): Promise<TaskId[]> {
        let commands: SyncAddItemRequest[] = args.map(arg => ({
            type: "item_add",
            uuid: randomUUID(),
            temp_id: randomUUID(),
            args: arg
        }));
        return this.makeSyncCommandRequest(...commands)
            .then(r => commands.map(c => c.temp_id).map(tempId => r.body.temp_id_mapping[tempId]))
    }

    public async createTask(data: CreateTaskApiRequest): Promise<HttpResponse<TaskApiResponse>> {
        return this.makeApiRequest<TaskApiResponse, CreateTaskApiRequest>("POST", "/tasks", data)
    }

    public async getTasks(projectId?: ProjectId): Promise<HttpResponse<TaskApiResponse[]>> {
        let searchQuery= ""
        if (projectId) {
            searchQuery += `?project_id=${projectId}`;
        }
        return this.makeApiRequest<TaskApiResponse[]>("GET", `/tasks${searchQuery}`)
    }

    public async getTask(taskId: TaskId): Promise<HttpResponse<TaskApiResponse>> {
        return this.makeApiRequest<TaskApiResponse>("GET", `/tasks/${taskId}`)
    }

    public async closeTask(taskId: TaskId): Promise<HttpResponse> {
        return this.makeApiRequest("POST", `/tasks/${taskId}/close`)
    }

    public async getLabels(): Promise<LabelResponse[]> {
        return this.makeApiRequest<LabelResponse[]>("GET", '/labels').then(this.handleResponse);
    }

    public async createLabel(data: CreateLabelApiRequest): Promise<LabelName> {
        return this.makeApiRequest<LabelResponse, CreateLabelApiRequest>("POST", "/labels", data)
            .then(res => this.handleResponse(res))
            .then(label => label.name)
    }

    public async getProjects(): Promise<TodoistProject[]> {
        return this.makeApiRequest<TodoistProject[]>("GET", '/projects').then(response => response.body);
    }

    public async createProject(name: string): Promise<TodoistProject> {
        const projectData = {
            name
        };
        return this.makeApiRequest<TodoistProject, CreateProjectRequest>("POST", "/projects", projectData)
            .then(response => response.body);
    }

    async deleteProject(projectId: ProjectId): Promise<HttpResponse> {
        return this.makeApiRequest("DELETE", `/projects/${projectId}`)
    }

    async deleteLabel(labelId: LabelId): Promise<HttpResponse> {
        return this.makeApiRequest("DELETE", `/labels/${labelId}`)
    }

    public async replaceLabels(taskId: TaskId, labels: LabelName[]): Promise<HttpResponse<TaskApiResponse>> {
        return this.updateTask(taskId, {labels: labels});
    }

    public async updateTask(taskId: TaskId, updates: Partial<UpdateTaskApiRequest>): Promise<HttpResponse<TaskApiResponse>> {
        return this.makeApiRequest<TaskApiResponse, Partial<UpdateTaskApiRequest>>("POST", `/tasks/${taskId}`, updates);
    }

    public async updateDueDateTasks(taskIds: TaskId[], dueDate: DueDate) {
        let commands: SyncItemsUpdateRequest[] = taskIds.map(taskId => ({
            type: "item_update",
            uuid: randomUUID(),
            args: {
                id: taskId,
                due: {date: dueDate}
            }
        }));
        return this.makeSyncCommandRequest(...commands)
    }

    private async makeApiRequest<Res = undefined, Req = undefined>(method: 'GET' | 'POST' | 'DELETE', endpoint: string, body?: Req): Promise<HttpResponse<Res>> {
        const response = await fetch(`${this.apiUrl}/rest/v2${endpoint}`, {
            method,
            headers: {
                'Authorization': `Bearer ${this.apiKey}`,
                'Content-Type': 'application/json',
            },
            body: body ? JSON.stringify(body) : undefined
        });
        return parseResponse(response)
    }


    private async makeSyncQueryRequest<Res = undefined>(...types: SyncQueryType[]): Promise<HttpResponse<Res>> {
        const response = await fetch(`${this.apiUrl}/sync/v9/sync`, {
            method: "POST",
            headers: {
                'Authorization': `Bearer ${this.apiKey}`,
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                sync_token: "*",
                resource_types: types,
            })
        });
        return parseResponse(response)
    }

    private async makeSyncCommandRequest(...commands: SyncCommandRequest []): Promise<HttpResponse<SyncCommandResponse>> {
        const response = await fetch(`${this.apiUrl}/sync/v9/sync`, {
            method: "POST",
            headers: {
                'Authorization': `Bearer ${this.apiKey}`,
                'Content-Type': 'application/json',
            },
            body: JSON.stringify({
                sync_token: "*",
                commands,
            })
        });
        return parseResponse(response)
    }

    private handleResponse<T>(response: HttpResponse<T>): T {
        if (!response.successful) {
            new Error(`Response wasn't successful status: '${response.status}' with body: '${response.body}'`)
        }
        return response.body
    }
}
