import {Task} from "../domain/task";
import {DoableTask} from "./DoableTask";
import {Day} from "../domain/Day";

function asDoableTask({
                          id,
                          content,
                          priority,
                          labels,
                          dueDate: optionalDueDate,
                          estimation: optionalEstimation,
                      }: Task,
                      today: Day): DoableTask {
    const dueDate = optionalDueDate!;
    const estimation = optionalEstimation!;
    const effectiveDueDate = dueDate > today ? dueDate : today
    return {
        id,
        content,
        priority,
        labels,
        dueDate,
        effectiveDueDate,
        estimation,
    }
}

export default asDoableTask
