import HotkeyConfirmation from "../shared/hotkeys/HotkeyConfirmation";
import {TaskId} from "../shared/TaskId";
import If from "../shared/components/If";
import dayjs from "../shared/dayjs";
import {RescheduleTaskPayload} from "../store";
import {period} from "../shared/Period";
import {ColorKey, getColorByKey, Hex} from "../shared/Color";

type Action = { label: string, amount: number, unit: "day" | "days" | "week" | "weeks", color?: Hex }

const daysColors: Record<string, string> = {
    "MON": getColorByKey(ColorKey.SKY_BLUE).value,
    "TUE": getColorByKey(ColorKey.GREEN).value,
    "WED": getColorByKey(ColorKey.YELLOW).value,
    "THU": getColorByKey(ColorKey.ORANGE).value,
    "FRI": getColorByKey(ColorKey.RED).value,
    "SAT": getColorByKey(ColorKey.GRAPE).value,
    "SUN": getColorByKey(ColorKey.BERRY_RED).value,

}

const actions: Action[] = [
    {label: "Tomorrow", amount: 1, unit: "day", color: getColorByKey(ColorKey.ORANGE).value},
    action(2, "days"),
    action(3, "days"),
    action(4, "days"),
    action(5, "days"),
    action(6, "days"),
    {label: "1 week", amount: 1, unit: "week"},
    {label: "2 weeks", amount: 2, unit: "weeks"},
]

function action(amount: number, unit: "days"): Action {
    return {label: dayjs().add(amount, unit).format("ddd"), amount, unit: unit}
}

interface RescheduleTaskProps {
    taskId: TaskId
    onReschedule: (payload: RescheduleTaskPayload) => void
}

export function RescheduleTask({taskId, onReschedule}: RescheduleTaskProps) {

    return <>{actions.map(({label, amount, unit, color}, index) => {
        const rColor = color ? color : daysColors[label.toUpperCase()]
        return <HotkeyConfirmation
            key={index}
            binding={`${index + 1}`}
            action={() => {
                onReschedule({taskId: taskId!, period: period(amount, unit)})
            }}
            label={label}
            color={rColor}
        />
    })}</>;
}
