import {TaskId} from "../shared/TaskId";
import {clock, Clock} from "../domain/Clock";
import {LocalRepository} from "../infrastructure/localstorage/LocalRepository";
import LocalStorageRepository from "../infrastructure/localstorage/LocalStorageRepository";
import {Day} from "../domain/Day";
import {objectKeys} from "../shared/objectKeys";

export type DailyTaskOrder = TaskId[]

export type WorkingPlan = Record<Day, DailyTaskOrder>


export class OrderRepository {

    private storage: LocalRepository<WorkingPlan>;
    private clock: Clock;

    constructor(storage: LocalRepository<WorkingPlan>, clock: Clock) {
        this.storage = storage;
        this.clock = clock;
    }

    load(): WorkingPlan {
        return this.storage.find() || {}
    }

    async store(day: Day, order: DailyTaskOrder) {
        const plan = this.storage.find() || {};
        objectKeys(plan).filter(key => key < this.clock.today()).forEach((key) => {
            delete plan[key];
        })
        plan[day] = order;
        this.storage.store(plan)
    }
}

export const orderRepository = new OrderRepository(new LocalStorageRepository<WorkingPlan>("__working-plan"), clock)


