import React from 'react';
import {useStoreState} from "../store";
import styles from "./Labels.module.css"
import {Label, LabelCategory} from "../domain/Label";

function Labels() {
    const labels = useStoreState(state => state.labels);

    const groupeByCategory: Record<LabelCategory, Label[]> = {
        [LabelCategory.BASIC]: [],
        [LabelCategory.ESTIMATION]: []
    }


    return <>
        <h2>
            Labels
        </h2>
        {Object.entries(Object.values(labels)
            .reduce((acc, label) => {
                acc[label.category].push(label)
                return acc
            }, groupeByCategory))
            .map(([category, labels]) => (<>
                <h3 className={styles.Category}>{category}</h3>
                <div className={styles.Labels}>
                    {labels.map(label => (
                        <div className={styles.Label}
                             style={{borderColor: label.color.value}}>{label.name}</div>
                    ))}
                </div>
            </>))}
    </>;
}

export default Labels;
