import {LabelResponse} from "./LabelResponse";
import {getColorByKey} from "../shared/Color";
import {LabelName} from "../shared/LabelName";
import {Minutes} from "../shared/Minutes";
import {Label, LabelCategory} from "../domain/Label";

export const timeLabelRegex = /^\d+[mhd]$/;

type CategorizedLabel = Omit<Label, "order">
type LabelsForEachCategory = Record<LabelCategory, CategorizedLabel[]>

const createLabelsForEachCategory = (): LabelsForEachCategory => (
    {
        [LabelCategory.BASIC]: [],
        [LabelCategory.ESTIMATION]: [],
    });
const compareFn: Record<LabelCategory, (a: CategorizedLabel, b: CategorizedLabel) => number> = {
    [LabelCategory.BASIC]: (a, b) => a.name.localeCompare(b.name),
    [LabelCategory.ESTIMATION]: (a, b) => extractMinutesFrom(a.name) - extractMinutesFrom(b.name),
}

export function asLabels(input: LabelResponse[]): Label[] {
    const unorderedLabels = input.map(asCategorizedLabel);
    const groupedByCategory = unorderedLabels.reduce<LabelsForEachCategory>((prev, curr) => {
        prev[curr.category].push(curr)
        return prev;
    }, createLabelsForEachCategory());
    return Object.entries(groupedByCategory).map(([key, value]) => {
        const enumKey = key as LabelCategory
        const compareFnElement = compareFn[enumKey];
        return value.sort(compareFnElement).map((it, index) =>
            ({...it, order: index}));
    }).flatMap(it => it)
}

function asCategorizedLabel(item: LabelResponse): CategorizedLabel {
    let timeBased = isTimeLabel(item.name);
    return ({
        name: item.name,
        color: getColorByKey(item.color),
        category: timeBased ? LabelCategory.ESTIMATION : LabelCategory.BASIC,
    });
}

export function isTimeLabel(name: LabelName): boolean {
    return timeLabelRegex.test(name)
}

export function extractMinutesFrom(name: LabelName): Minutes {
    if (name.endsWith("m")) {
        return parseInt(name.slice(0, -1));
    }
    if (name.endsWith("h")) {
        return parseInt(name.slice(0, -1)) * 60;
    }

    if (name.endsWith("d")) {
        return parseInt(name.slice(0, -1)) * 60 * 24;
    }

    throw new Error(`Can't extract minutes from label: '${name}'`)
}
