import {useMemo} from "react";
import {useStoreState} from "../store";
import {LabelName} from "./LabelName";
import {Hex} from "./Color";
import {LabelCategory} from "../domain/Label";

export type LabelInfo = Record<LabelName, {
    color: Hex
}>

export function useEstimationLabels() {
    const labels = useStoreState(state => state.labels);
    return useMemo(() => {
        return Object.values(labels).filter(label => label.category === LabelCategory.ESTIMATION).reduce<LabelInfo>((acc, label) => {
            acc[label.name] = {
                color: label.color.value
            }
            return acc;
        }, {})

    }, [labels]);
}
