import {DoableTask} from "./DoableTask";
import {DAY_LIMIT, useStoreActions, useStoreState} from "../store";
import {useEffect, useState} from "react";
import {TaskId} from "../shared/TaskId";
import {period} from "../shared/Period";
import {getEstimationLabel} from "../todoist/getEstimationLabel";
import Progress from "./Progress";
import Work from "./Work";
import {humanizeDueDay} from "../shared/humanizeDueDay";
import {clock} from "../domain/Clock";
import Timer from "./Timer";
import Footer from "../layout/Footer";
import styles from "./WorkPage.module.css";
import {HotKey} from "../shared/hotkeys/HotKey";
import Icon from "../shared/Icon";
import {asWorkableTasks} from "./asWorkableTasks";
import useMinutesUntil from "./useMinutesUntil";
import SidebarRight from "../layout/SidebarRight";
import HotkeyConfirmation from "../shared/hotkeys/HotkeyConfirmation";
import Header from "../layout/Header";


interface WorkingProps {
    tasks: DoableTask[]
}

function Working({tasks}: WorkingProps) {
    let {
        labels,
        inProgressTask,
        processingTasks,
        timeLabels,
    } = useStoreState(state => state);

    let {
        startWorkingOnTask: start,
        stopWorkingOnTask: stop,
        completeTask,
        rescheduleTask,
        estimate,
        taskOrderMove
    } = useStoreActions(actions => actions);
    const [currentTaskId, setCurrentTaskId] = useState<TaskId>(tasks[0].id)
    const currentTaskIndex = tasks.findIndex(task => task.id === currentTaskId)

    useEffect(() => {
        openActiveTask()
    }, [])

    const currentTask = (): DoableTask => {
        return tasks[currentTaskIndex] || tasks[0]
    }

    let next = () => {
        if (currentTaskIndex < tasks.length - 1) {
            setCurrentTaskId(tasks[currentTaskIndex + 1].id);
        }
    }

    let prev = () => {
        if (currentTaskIndex > 0) {
            setCurrentTaskId(tasks[currentTaskIndex - 1].id);
        }
    }

    let openActiveTask = () => {
        if (inProgressTask) {
            setCurrentTaskId(inProgressTask?.id)
        }
    }

    let performStart = () => {
        start(currentTask().id)
    }

    let performStop = () => {
        stop(currentTaskId)
    }

    function performComplete() {
        keepSelectedTask(() => {
            performStop();
            completeTask(currentTask().id);
        })
    }

    function keepSelectedTask(callback: () => void) {
        setCurrentTaskId(tasks[Math.min(currentTaskIndex + 1, tasks.length - 2)].id)
        callback()
    }

    function performPostpone() {
        keepSelectedTask(() => {
            rescheduleTask({
                taskId: currentTask().id,
                period: period(1, "day")
            })
        })
    }

    const noActiveTask = !inProgressTask;
    const taskIsActive = currentTask().id === inProgressTask?.id;
    const ongoingTask = inProgressTask && currentTask().id !== inProgressTask.id

    const color = labels[getEstimationLabel(currentTask().labels)].color.value

    const startedAt = inProgressTask && inProgressTask.id === currentTask().id ? inProgressTask.startedAt : undefined

    const availableMinutes = useMinutesUntil(DAY_LIMIT);

    return <>
        <Header>
            <div className={styles.Header}>
                <HotKey binding="comma"
                        label="First"
                        disabled={true}
                        onClick={() =>
                            taskOrderMove({
                                taskId: currentTaskId,
                                day: currentTask().effectiveDueDate,
                                operation: "highest"
                            })
                        }/>
                <HotKey binding="shift + left"
                        label="Move left"
                        disabled={true}
                        onClick={() => taskOrderMove({
                            taskId: currentTaskId,
                            day: currentTask().effectiveDueDate,
                            operation: "higher"
                        })}/>
                <HotKey binding="shift + right"
                        label="Move right"
                        disabled={true}
                        onClick={() => taskOrderMove({
                            taskId: currentTaskId,
                            day: currentTask().effectiveDueDate,
                            operation: "lower"
                        })}/>
                <HotKey binding="period"
                        label="Last"
                        disabled={true}
                        onClick={() => taskOrderMove({
                            taskId: currentTaskId,
                            day: currentTask().effectiveDueDate,
                            operation: "lowest"
                        })}/>
            </div>
        </Header>
        <Progress currentId={currentTask().id} tasks={asWorkableTasks(tasks)}
                  availableMinutes={availableMinutes} loading={processingTasks}/>
        <Work task={currentTask()} humanizedDay={humanizeDueDay(clock.today(), currentTask().dueDate)}
              loading={processingTasks}>
            <Timer duration={currentTask().estimation.duration} color={color} startedAt={startedAt} loading={processingTasks}/>
            <Footer>
                <div className={styles.Footer}>
                    <div className={styles.Navigation}>
                        <HotKey binding="left"
                                label="Prev"
                                disabled={currentTaskIndex === 0}
                                loading={processingTasks}
                                onClick={prev}/>
                        <HotKey binding="right"
                                label="Next"
                                revert
                                loading={processingTasks}
                                disabled={currentTaskIndex === tasks.length - 1}
                                onClick={next}/>
                    </div>
                    <div className={styles.Completion}>
                        <HotkeyConfirmation
                            binding="t"
                            action={performPostpone}
                            label={<Icon name="forward-step.svg"/>}
                            loading={processingTasks}/>
                        {noActiveTask &&
                            <HotKey binding="enter"
                                    label={<Icon name="play.svg"/>}
                                    loading={processingTasks}
                                    onClick={performStart}/>
                        }
                        {taskIsActive &&
                            <HotkeyConfirmation
                                binding="enter"
                                action={performStop}
                                label={<Icon name="stop.svg"/>}
                                loading={processingTasks}/>
                        }
                        {ongoingTask &&
                            <HotKey binding="enter"
                                    label={<Icon name="hammer.svg"/>}
                                    loading={processingTasks}
                                    onClick={openActiveTask}/>
                        }
                        <HotkeyConfirmation
                            binding="shift + enter"
                            action={performComplete}
                            label={<Icon name="check.svg"/>}
                            loading={processingTasks}/>
                    </div>
                </div>
            </Footer>
            <SidebarRight>
                <div className={styles.Labels}>
                    {timeLabels.map((label, index) => {
                            let shortcutKey = `${index + 1}`
                            return <HotKey key={shortcutKey}
                                           binding={`shift + ${shortcutKey}`}
                                           label={label.name}
                                           loading={processingTasks}
                                           color={label.color.value}
                                           onClick={() => {
                                               estimate({taskId: currentTaskId, label: label.name})
                                           }}/>
                        }
                    )}
                </div>
            </SidebarRight>
        </Work>
    </>

}

export default Working
