import dayjs from "./dayjs";
import {Day} from "../domain/Day";

export interface HumanizedDay {
    dayDiff: number,
    text: string
}

export const humanizeDueDay = (today: Day, value: Day): HumanizedDay => {
    let parsedValue = parse(value);
    let parsedToday = parse(today);
    let diff = parsedValue.diff(parsedToday, "days");
    switch (diff) {
        case 0:
            return {dayDiff: diff, text: "Today"};
        case 1:
            return {dayDiff: diff, text: "Tomorrow"};
        case -1:
            return {dayDiff: diff, text: "Yesterday"};
        default:
            return {dayDiff: diff, text: dayjs.duration(parsedValue.diff(parsedToday)).humanize(true)};
    }
}

function parse(value: Day) {
    return dayjs(value).startOf("day");
}
