import {DueDate} from "../todoist/DueDate";
import {TaskId} from "../shared/TaskId";
import {Priority} from "../shared/Priority";

interface SortableTask {
    id: TaskId;
    dueDate?: DueDate;
    priority: Priority;
    content: string;
}

function sortDueDates(a: DueDate | undefined, b: DueDate | undefined): number {
    if (a === b) {
        return 0;
    }
    if (a === undefined) {
        return -1;
    }
    if (b === undefined) {
        return 1;
    }
    return a.localeCompare(b)
}

export function sortTasks(a: SortableTask, b: SortableTask) {
    return sortDueDates(a.dueDate, b.dueDate) ||
        b.priority - a.priority || a.content.localeCompare(b.content);
}
